import { Controller, Get, Param, ParseIntPipe, Query } from "@nestjs/common";
import {
  ApiNotFoundResponse,
  ApiOkResponse,
  ApiOperation,
  ApiParam,
  ApiTags,
} from '@nestjs/swagger';
import { AutocompleteQueryDto } from 'src/_utils/dto/requests/autocomplete-query.dto';
import { AutocompleteOptionDto } from 'src/_utils/dto/responses/autocomplete-option.dto';
import { RestaurantDetailsDto } from './_utils/dto/response/restaurant-details.dto';
import { RestaurantsService } from './restaurants.service';

@ApiTags("Restaurants")
@Controller("restaurants")
export class RestaurantsController {
  constructor(private readonly restaurantsService: RestaurantsService) {}

  @Get('filters/cuisines')
  @ApiOperation({ summary: 'Cuisines for autocomplete (optional `q` substring filter).' })
  @ApiOkResponse({ type: [AutocompleteOptionDto] })
  autocompleteCuisines(
    @Query() query: AutocompleteQueryDto,
  ): Promise<AutocompleteOptionDto[]> {
    return this.restaurantsService.autocompleteCuisines(query.q, query.limit);
  }

  @Get("filters/facilities")
  @ApiOperation({
    summary: "Facilities for autocomplete (optional `q` substring filter).",
  })
  @ApiOkResponse({ type: [AutocompleteOptionDto] })
  autocompleteFacilities(
    @Query() query: AutocompleteQueryDto,
  ): Promise<AutocompleteOptionDto[]> {
    return this.restaurantsService.autocompleteFacilities(query.q, query.limit);
  }

  @Get(":restaurantId")
  @ApiParam({ type: "number", name: "restaurantId" })
  @ApiOperation({ summary: "Get restaurant details by ID." })
  @ApiOkResponse({ type: RestaurantDetailsDto })
  @ApiNotFoundResponse({ description: "Restaurant not found." })
  getRestaurantById(
    @Param("restaurantId", ParseIntPipe) restaurantId: number,
  ): Promise<RestaurantDetailsDto> {
    return this.restaurantsService.getRestaurantById(restaurantId);
  }
}

import { Injectable, NotFoundException } from "@nestjs/common";
import {
  and,
  asc,
  desc,
  eq,
  ilike,
  inArray,
  notInArray,
  or,
  sql,
  type SQL,
} from "drizzle-orm";
import type { AnyPgTable, PgColumn } from "drizzle-orm/pg-core";
import { DatabaseService } from "src/database/database.service";
import { GREEN_STAR_CODE, MICHELIN_STAR_CODE } from "./_constants";
import {
  SearchRestaurantsQueryDto,
} from "./_utils/dto/request/search-restaurants.query.dto";
import { RestaurantDetailsDto } from "./_utils/dto/response/restaurant-details.dto";
import {
  awardTypes,
  cities,
  countries,
  cuisines,
  facilities,
  restaurantAwards,
  restaurantCuisines,
  restaurantFacilities,
  restaurants,
  restaurantImages,
} from "./entities";
import { AutocompleteHelper } from "src/_shared/autocomplete/autocomplete.helper";
import { AutocompleteOptionDto } from "src/_utils/dto/responses/autocomplete-option.dto";

@Injectable()
export class RestaurantsService {
  constructor(
    private readonly databaseService: DatabaseService,
    private readonly autocompleteHelper: AutocompleteHelper,
  ) {}

  getRestaurantById = async (id: number): Promise<RestaurantDetailsDto> => {
    const [result] = await this.databaseService.db
      .select({
        id: restaurants.id,
        name: restaurants.name,
        address: restaurants.address,
        description: restaurants.description,
        sourceUrl: restaurants.sourceUrl,
        websiteUrl: restaurants.websiteUrl,
        latitude: restaurants.latitude,
        longitude: restaurants.longitude,
        phoneNumber: restaurants.phoneNumber,
        createdAt: restaurants.createdAt,
        cityId: cities.id,
        city: cities.name,
        countryId: countries.id,
        country: countries.name,
        awardCode: sql<string | null>`(
          SELECT ${awardTypes.code}
          FROM ${restaurantAwards}
          INNER JOIN ${awardTypes} ON ${awardTypes.id} = ${restaurantAwards.awardTypeId}
          WHERE ${restaurantAwards.restaurantId} = ${restaurants.id}
          ORDER BY CASE WHEN ${awardTypes.code} = ${GREEN_STAR_CODE} THEN 1 ELSE 0 END, ${awardTypes.code}
          LIMIT 1
        )`,
        stars: sql<number | null>`(
          SELECT MAX(${restaurantAwards.starsCount})
          FROM ${restaurantAwards}
          WHERE ${restaurantAwards.restaurantId} = ${restaurants.id}
        )`,
        hasGreenStar: sql<boolean>`coalesce((
          SELECT BOOL_OR(${awardTypes.code} = ${GREEN_STAR_CODE})
          FROM ${restaurantAwards}
          INNER JOIN ${awardTypes} ON ${awardTypes.id} = ${restaurantAwards.awardTypeId}
          WHERE ${restaurantAwards.restaurantId} = ${restaurants.id}
        ), false)`,
        cuisines: this.cuisinesAggSql,
        facilities: this.facilitiesAggSql,
        images: this.imagesAggSql,
        priceLevel: restaurants.priceLevel,
      })
      .from(restaurants)
      .innerJoin(cities, eq(cities.id, restaurants.cityId))
      .innerJoin(countries, eq(countries.id, cities.countryId))
      .where(eq(restaurants.id, id))
      .limit(1);

    if (!result) {
      throw new NotFoundException("Restaurant not found");
    }

    return result as RestaurantDetailsDto;
  };

  autocompleteCuisines = (q: string | undefined, limit: number): Promise<AutocompleteOptionDto[]> =>
    this.autocompleteHelper.autocompleteOptions({
      table: cuisines,
      idColumn: cuisines.id,
      nameColumn: cuisines.name,
      normalizedColumn: cuisines.normalizedName,
      q,
      limit,
    });

  autocompleteFacilities = (q: string | undefined, limit: number): Promise<AutocompleteOptionDto[]> =>
    this.autocompleteHelper.autocompleteOptions({
      table: facilities,
      idColumn: facilities.id,
      nameColumn: facilities.name,
      normalizedColumn: facilities.normalizedName,
      q,
      limit,
    });

  private readonly cuisinesAggSql = sql<string[]>`coalesce((
    SELECT array_agg(${cuisines.name} ORDER BY ${cuisines.name})
    FROM ${restaurantCuisines}
    INNER JOIN ${cuisines} ON ${cuisines.id} = ${restaurantCuisines.cuisineId}
    WHERE ${restaurantCuisines.restaurantId} = ${restaurants.id}
  ), ARRAY[]::text[])`;

  private readonly facilitiesAggSql = sql<string[]>`coalesce((
    SELECT array_agg(${facilities.name} ORDER BY ${facilities.name})
    FROM ${restaurantFacilities}
    INNER JOIN ${facilities} ON ${facilities.id} = ${restaurantFacilities.facilityId}
    WHERE ${restaurantFacilities.restaurantId} = ${restaurants.id}
  ), ARRAY[]::text[])`;

  private readonly imagesAggSql = sql<string[]>`coalesce((
    SELECT array_agg(${restaurantImages.imageUrl} ORDER BY ${restaurantImages.id})
    FROM ${restaurantImages}
    WHERE ${restaurantImages.restaurantId} = ${restaurants.id}
  ), ARRAY[]::text[])`;

  private getTextClause = ({
    search,
  }: SearchRestaurantsQueryDto): SQL | undefined => {
    const trimmed = search?.trim();
    if (!trimmed) return undefined;
    return or(
      ilike(restaurants.name, `%${trimmed}%`),
      ilike(restaurants.description, `%${trimmed}%`),
    );
  };

  private getCityClause = ({
    cityId,
  }: SearchRestaurantsQueryDto): SQL | undefined =>
    cityId !== undefined && cityId !== null ? eq(cities.id, cityId) : undefined;

  private getCountryClause = ({
    countryId,
  }: SearchRestaurantsQueryDto): SQL | undefined =>
    countryId !== undefined && countryId !== null
      ? eq(cities.countryId, countryId)
      : undefined;

  private getCuisinesClause = ({
    cuisineIds,
  }: SearchRestaurantsQueryDto): SQL | undefined =>
    cuisineIds?.length
      ? inArray(
          restaurants.id,
          this.databaseService.db
            .select({ id: restaurantCuisines.restaurantId })
            .from(restaurantCuisines)
            .where(inArray(restaurantCuisines.cuisineId, cuisineIds)),
        )
      : undefined;

  private getFacilitiesClause = ({
    facilityIds,
  }: SearchRestaurantsQueryDto): SQL | undefined =>
    facilityIds?.length
      ? inArray(
          restaurants.id,
          this.databaseService.db
            .select({ id: restaurantFacilities.restaurantId })
            .from(restaurantFacilities)
            .where(inArray(restaurantFacilities.facilityId, facilityIds)),
        )
      : undefined;

  /**
   * Award filter: when `minStars`/`maxStars` is set without `awardCode`, implicitly restricts
   * to MICHELIN_STAR awards (Bib Gourmand / Selected have no stars, so the filter would always
   * return 0 results otherwise).
   */
  private getAwardsClause = ({
    awardCode,
    minStars,
    maxStars,
  }: SearchRestaurantsQueryDto): SQL | undefined => {
    const hasStarsFilter = minStars !== undefined || maxStars !== undefined;
    const trimmedCode = awardCode?.trim();
    if (!hasStarsFilter && !trimmedCode) return undefined;

    const effectiveCode =
      trimmedCode ?? (hasStarsFilter ? MICHELIN_STAR_CODE : undefined);

    const clauses = [
      effectiveCode ? eq(awardTypes.code, effectiveCode) : undefined,
      minStars !== undefined
        ? sql`${restaurantAwards.starsCount} >= ${minStars}`
        : undefined,
      maxStars !== undefined
        ? sql`${restaurantAwards.starsCount} <= ${maxStars}`
        : undefined,
    ].filter((clause): clause is SQL => Boolean(clause));

    return inArray(
      restaurants.id,
      this.databaseService.db
        .select({ id: restaurantAwards.restaurantId })
        .from(restaurantAwards)
        .innerJoin(awardTypes, eq(awardTypes.id, restaurantAwards.awardTypeId))
        .where(and(...clauses)),
    );
  };

  private getGreenStarClause = ({
    greenStar,
  }: SearchRestaurantsQueryDto): SQL | undefined => {
    if (greenStar === undefined) return undefined;
    const withGreen = this.databaseService.db
      .select({ id: restaurantAwards.restaurantId })
      .from(restaurantAwards)
      .innerJoin(awardTypes, eq(awardTypes.id, restaurantAwards.awardTypeId))
      .where(eq(awardTypes.code, GREEN_STAR_CODE));
    return greenStar
      ? inArray(restaurants.id, withGreen)
      : notInArray(restaurants.id, withGreen);
  };

  private getPricesClause = ({
    minPriceLevel,
    maxPriceLevel,
  }: SearchRestaurantsQueryDto): SQL | undefined => {
    const clauses = [
      minPriceLevel
        ? sql`${restaurants.priceLevel} >= ${minPriceLevel}`
        : undefined,
      maxPriceLevel
        ? sql`${restaurants.priceLevel} <= ${maxPriceLevel}`
        : undefined,
    ].filter((clause): clause is SQL => Boolean(clause));
    return clauses.length > 0 ? and(...clauses) : undefined;
  };

  private autocompleteOptions = async (params: {
    table: AnyPgTable;
    idColumn: PgColumn;
    nameColumn: PgColumn;
    normalizedColumn?: PgColumn;
    additionalWhere?: SQL;
    q: string | undefined;
    limit: number;
  }): Promise<AutocompleteOptionDto[]> => {
    const {
      table,
      idColumn,
      nameColumn,
      normalizedColumn,
      additionalWhere,
      q,
      limit,
    } = params;
    const safe = this.getSafeAutocompleteTerm(q);
    const pattern = safe ? `%${safe}%` : undefined;

    const nameMatch = pattern
      ? normalizedColumn
        ? or(ilike(nameColumn, pattern), ilike(normalizedColumn, pattern))
        : ilike(nameColumn, pattern)
      : undefined;
    const whereExpr = and(
      ...[additionalWhere, nameMatch].filter((clause): clause is SQL =>
        Boolean(clause),
      ),
    );

    const base = this.databaseService.db
      .select({ id: idColumn, name: nameColumn })
      .from(table)
      .where(whereExpr);

    const query = safe
      ? base.orderBy(
          asc(
            this.autocompleteNameMatchPriority(nameColumn, safe, {
              normalizedColumn,
            }),
          ),
          asc(nameColumn),
        )
      : base.orderBy(asc(nameColumn));

    const rows = await query.limit(limit);
    return rows.map((row) => ({
      id: row.id as number,
      name: row.name as string,
    }));
  };

  private getSafeAutocompleteTerm = (
    q: string | undefined,
  ): string | undefined => {
    const trimmed = q?.trim();
    if (!trimmed) return undefined;
    const safe = trimmed.replace(/[%_]/g, "").slice(0, 100);
    return safe || undefined;
  };

  getAllRestaurantsWithSourceUrl = async (): Promise<
    Array<{ id: number; sourceUrl: string }>
  > => {
    return this.databaseService.db
      .select({
        id: restaurants.id,
        sourceUrl: restaurants.sourceUrl,
      })
      .from(restaurants)
      .where(sql`${restaurants.sourceUrl} IS NOT NULL`)
      .orderBy(asc(restaurants.id));
  };

  bulkInsertRestaurantImages = async (
    images: Array<{ restaurantId: number; imageUrl: string }>,
  ): Promise<void> => {
    if (images.length === 0) return;

    await this.databaseService.db
      .insert(restaurantImages)
      .values(images)
      .onConflictDoNothing();
  };

  /**
   * Get restaurant IDs that don't have any images yet
   * @param restaurantIds Array of restaurant IDs to check
   * @returns Array of restaurant IDs without images
   */
  getRestaurantsWithoutImages = async (
    restaurantIds: number[],
  ): Promise<number[]> => {
    if (restaurantIds.length === 0) return [];

    // Get IDs that have images
    const restaurantsWithImages = await this.databaseService.db
      .selectDistinct({ id: restaurantImages.restaurantId })
      .from(restaurantImages)
      .where(inArray(restaurantImages.restaurantId, restaurantIds));

    const idsWithImages = new Set(restaurantsWithImages.map((r) => r.id));

    // Return IDs that don't have images
    return restaurantIds.filter((id) => !idsWithImages.has(id));
  };

  /**
   * 0 = whole label or any token (split on spaces / commas / slashes / hyphens) starts with the term
   * 1 = contains term but no "prefix" match (neither on full string nor on a word)
   * 2 = fallback
   */
  private autocompleteNameTokensStartWith = (
    nameColumn: PgColumn,
    prefix: string,
  ): SQL =>
    sql`EXISTS (
      SELECT 1
      FROM unnest(
        string_to_array(
          trim(
            regexp_replace(
              regexp_replace(cast(${nameColumn} as text), E'[,\\-–—/]+', ' ', 'g'),
              E'\\s+',
              ' ',
              'g'
            )
          ),
          ' '
        )
      ) AS t(token)
      WHERE btrim(t.token) <> '' AND t.token ILIKE ${prefix}
    )`;

  private autocompleteNameMatchPriority = (
    nameColumn: PgColumn,
    safe: string,
    options?: { normalizedColumn?: PgColumn },
  ): SQL => {
    const prefix = `${safe}%`;
    const contains = `%${safe}%`;
    const norm = options?.normalizedColumn;
    if (norm) {
      return sql`(
        CASE
          WHEN ${nameColumn} ILIKE ${prefix}
            OR ${norm} ILIKE ${prefix}
            OR ${this.autocompleteNameTokensStartWith(nameColumn, prefix)}
            OR ${this.autocompleteNameTokensStartWith(norm, prefix)}
          THEN 0
          WHEN ${nameColumn} ILIKE ${contains} OR ${norm} ILIKE ${contains}
          THEN 1
          ELSE 2
        END
      )`;
    }
    return sql`(
      CASE
        WHEN ${nameColumn} ILIKE ${prefix} OR ${this.autocompleteNameTokensStartWith(nameColumn, prefix)}
        THEN 0
        WHEN ${nameColumn} ILIKE ${contains}
        THEN 1
        ELSE 2
      END
    )`;
  };
}

import {
  BadRequestException,
  ForbiddenException,
  Injectable,
  NotFoundException,
} from '@nestjs/common';
import { GetUserType } from 'src/users/users.entity';
import { UserRoleEnum } from 'src/users/_utils/user-role.enum';
import { CreateRestaurantListDto } from './_utils/dto/request/create-restaurant-list.dto';
import { RenameRestaurantListDto } from './_utils/dto/request/rename-restaurant-list.dto';
import { RestaurantListContentDto } from './_utils/dto/response/restaurant-list-content.dto';
import { RestaurantListDto } from './_utils/dto/response/restaurant-list.dto';
import { normalizeRestaurantListName } from './_utils/functions/normalize-restaurant-list-name.function';
import { RestaurantListsMapper } from './restaurant-lists.mapper';
import { RestaurantListsRepository } from './restaurant-lists.repository';

@Injectable()
export class RestaurantListsService {
  private readonly listNotFound = new NotFoundException('List not found');
  private readonly listNameAlreadyExists = new BadRequestException('A list with this name already exists');

  constructor(
    private readonly restaurantListsRepository: RestaurantListsRepository,
    private readonly restaurantListsMapper: RestaurantListsMapper,
  ) {}

  async getListsByUserId(userId: number, connectedUser: GetUserType): Promise<RestaurantListDto[]> {
    this.assertUserCanAccessLists(userId, connectedUser);

    const lists = await this.restaurantListsRepository.findListsByUserIdWithItemsCount(userId);
    return lists.map(this.restaurantListsMapper.toRestaurantListDto);
  }

  async getListContentById(
    userId: number,
    listId: number,
    connectedUser: GetUserType,
  ): Promise<RestaurantListContentDto> {
    this.assertUserCanAccessLists(userId, connectedUser);

    const list = await this.restaurantListsRepository.findListById(userId, listId);
    if (!list) {
      throw this.listNotFound;
    }

    const restaurants = await this.restaurantListsRepository.findRestaurantsByListId(list.id);
    return this.restaurantListsMapper.toRestaurantListContentDto(list, restaurants);
  }

  async getListContentByName(
    userId: number,
    listName: string,
    connectedUser: GetUserType,
  ): Promise<RestaurantListContentDto> {
    this.assertUserCanAccessLists(userId, connectedUser);

    const normalizedName = normalizeRestaurantListName(listName);
    const list = await this.restaurantListsRepository.findListByNormalizedName(userId, normalizedName);
    if (!list) {
      throw this.listNotFound;
    }

    const restaurants = await this.restaurantListsRepository.findRestaurantsByListId(list.id);
    return this.restaurantListsMapper.toRestaurantListContentDto(list, restaurants);
  }

  async createList(
    userId: number,
    dto: CreateRestaurantListDto,
    connectedUser: GetUserType,
  ): Promise<RestaurantListDto> {
    this.assertUserCanAccessLists(userId, connectedUser);

    const normalizedName = normalizeRestaurantListName(dto.name);

    try {
      const list = await this.restaurantListsRepository.createList(userId, dto.name, normalizedName);
      return this.restaurantListsMapper.toRestaurantListDtoFromEntity(list, 0);
    } catch (error) {
      if (this.isUniqueViolation(error)) {
        throw this.listNameAlreadyExists;
      }
      throw error;
    }
  }

  async renameList(
    userId: number,
    listId: number,
    dto: RenameRestaurantListDto,
    connectedUser: GetUserType,
  ): Promise<RestaurantListDto> {
    this.assertUserCanAccessLists(userId, connectedUser);

    const existingList = await this.restaurantListsRepository.findListById(userId, listId);
    if (!existingList) {
      throw this.listNotFound;
    }

    const normalizedName = normalizeRestaurantListName(dto.name);
    try {
      const updated = await this.restaurantListsRepository.renameList(userId, listId, dto.name, normalizedName);
      if (!updated) {
        throw this.listNotFound;
      }

      const itemsCount = await this.restaurantListsRepository.countItemsByListId(listId);
      return this.restaurantListsMapper.toRestaurantListDtoFromEntity(updated, itemsCount);
    } catch (error) {
      if (this.isUniqueViolation(error)) {
        throw this.listNameAlreadyExists;
      }
      throw error;
    }
  }

  async deleteList(userId: number, listId: number, connectedUser: GetUserType): Promise<void> {
    this.assertUserCanAccessLists(userId, connectedUser);

    const existingList = await this.restaurantListsRepository.findListById(userId, listId);
    if (!existingList) {
      throw this.listNotFound;
    }

    await this.restaurantListsRepository.deleteList(userId, listId);
  }

  private assertUserCanAccessLists(userId: number, connectedUser: GetUserType): void {
    if (connectedUser.role === UserRoleEnum.ADMIN) {
      return;
    }

    if (connectedUser.id === userId) {
      return;
    }

    throw new ForbiddenException('FORBIDDEN');
  }

  private isUniqueViolation(error: unknown): boolean {
    return (error as { code?: string })?.code === '23505';
  }
}
import { Injectable, InternalServerErrorException } from '@nestjs/common';
import { and, asc, desc, eq, sql } from 'drizzle-orm';
import { schema } from 'src/database/database.schema';
import { DatabaseService } from 'src/database/database.service';
import { SelectRestaurantList } from './restaurant-lists.entity';

export interface RestaurantListWithItemsCountRow {
  id: number;
  name: string;
  createdAt: Date;
  updatedAt: Date;
  itemsCount: number;
}

export interface RestaurantListRestaurantRow {
  id: number;
  name: string;
  addedAt: Date;
}

@Injectable()
export class RestaurantListsRepository {
  constructor(private readonly databaseService: DatabaseService) {}

  findListsByUserIdWithItemsCount(userId: number): Promise<RestaurantListWithItemsCountRow[]> {
    return this.databaseService.db
      .select({
        id: schema.restaurantLists.id,
        name: schema.restaurantLists.name,
        createdAt: schema.restaurantLists.createdAt,
        updatedAt: schema.restaurantLists.updatedAt,
        itemsCount: sql<number>`cast(count(${schema.restaurantListRestaurants.restaurantId}) as int)`,
      })
      .from(schema.restaurantLists)
      .leftJoin(
        schema.restaurantListRestaurants,
        eq(schema.restaurantListRestaurants.listId, schema.restaurantLists.id),
      )
      .where(eq(schema.restaurantLists.userId, userId))
      .groupBy(
        schema.restaurantLists.id,
        schema.restaurantLists.name,
        schema.restaurantLists.createdAt,
        schema.restaurantLists.updatedAt,
      )
      .orderBy(asc(schema.restaurantLists.createdAt));
  }

  async findListById(userId: number, listId: number): Promise<SelectRestaurantList | null> {
    const lists = await this.databaseService.db
      .select()
      .from(schema.restaurantLists)
      .where(
        and(
          eq(schema.restaurantLists.id, listId),
          eq(schema.restaurantLists.userId, userId),
        ),
      )
      .limit(1);

    return lists[0] ?? null;
  }

  async findListByNormalizedName(userId: number, normalizedName: string): Promise<SelectRestaurantList | null> {
    const lists = await this.databaseService.db
      .select()
      .from(schema.restaurantLists)
      .where(
        and(
          eq(schema.restaurantLists.userId, userId),
          eq(schema.restaurantLists.normalizedName, normalizedName),
        ),
      )
      .limit(1);

    return lists[0] ?? null;
  }

  findRestaurantsByListId(listId: number): Promise<RestaurantListRestaurantRow[]> {
    return this.databaseService.db
      .select({
        id: schema.restaurants.id,
        name: schema.restaurants.name,
        addedAt: schema.restaurantListRestaurants.addedAt,
      })
      .from(schema.restaurantListRestaurants)
      .innerJoin(
        schema.restaurants,
        eq(schema.restaurants.id, schema.restaurantListRestaurants.restaurantId),
      )
      .where(eq(schema.restaurantListRestaurants.listId, listId))
      .orderBy(desc(schema.restaurantListRestaurants.addedAt));
  }

  async countItemsByListId(listId: number): Promise<number> {
    const [result] = await this.databaseService.db
      .select({
        count: sql<number>`cast(count(${schema.restaurantListRestaurants.restaurantId}) as int)`,
      })
      .from(schema.restaurantListRestaurants)
      .where(eq(schema.restaurantListRestaurants.listId, listId));

    return result?.count ?? 0;
  }

  async createList(userId: number, name: string, normalizedName: string): Promise<SelectRestaurantList> {
    const lists = await this.databaseService.db
      .insert(schema.restaurantLists)
      .values({
        userId,
        name,
        normalizedName,
      })
      .returning();

    const list = lists[0];
    if (!list) {
      throw new InternalServerErrorException('Failed to create list');
    }

    return list;
  }

  async renameList(
    userId: number,
    listId: number,
    name: string,
    normalizedName: string,
  ): Promise<SelectRestaurantList | null> {
    const lists = await this.databaseService.db
      .update(schema.restaurantLists)
      .set({
        name,
        normalizedName,
        updatedAt: new Date(),
      })
      .where(
        and(
          eq(schema.restaurantLists.id, listId),
          eq(schema.restaurantLists.userId, userId),
        ),
      )
      .returning();

    return lists[0] ?? null;
  }

  async deleteList(userId: number, listId: number): Promise<void> {
    await this.databaseService.db
      .delete(schema.restaurantLists)
      .where(
        and(
          eq(schema.restaurantLists.id, listId),
          eq(schema.restaurantLists.userId, userId),
        ),
      );
  }
}

import { Controller, Get, Req, Res, UseGuards } from "@nestjs/common";
import { ConfigService } from "@nestjs/config";
import { AuthGuard } from "@nestjs/passport";
import { ApiOperation, ApiQuery, ApiTags } from "@nestjs/swagger";
import { Request, Response } from "express";
